import React, { useState } from 'react';
import { useForm } from 'react-hook-form';
import './Contact.css';
import { init, sendForm } from 'emailjs-com';
init("user_Boc5zsTh76kXC3qdiR1Fa");


// eslint-disable-next-line react-hooks/rules-of-hooks



const Contact = () => {


  const { register, handleSubmit, watch, errors } = useForm();
  const onSubmit = () => {

  const statusMessage = document.querySelector('.status-message');
  const form = document.querySelector('#contact-form');
  generateContactNumber();
  sendForm('default_service', 'template_32681fl', '#contact-form')
    .then(function (response) {
      console.log('SUCCESS!', response.status, response.text);
      form.reset();
      setStatusMessage("Message sent!");
      statusMessage.className = "status-message success";
      setTimeout(() => {
        statusMessage.className = 'status-message'
      }, 5000)
    }, function (error) {
      console.log('FAILED...', error);
      setStatusMessage("Failed to send message! Please try again later.");
      statusMessage.className = "status-message failure";
      setTimeout(() => {
        statusMessage.className = 'status-message'
      }, 5000)
    });
}
  const message = watch('message') || "";
  const messageCharsLeft = 1500 - message.length;
  const [contactNumber, setContactNumber] = useState("000000");
  const [statusMessage, setStatusMessage] = useState("Message");
  const generateContactNumber = () => {
  const numStr = "000000" + (Math.random() * 1000000 | 0);
  setContactNumber(numStr.substring(numStr.length - 6));
}

  return (
    <div className='contact'>
      <h1>Contact</h1>
      <p className='status-message'>{statusMessage}</p>
      <form id='contact-form' onSubmit={handleSubmit(onSubmit)}>
        <input type='hidden' name='contact_number' value={contactNumber} />
        <input
        type='text'
        name='user_name'
        ref={register}
        placeholder='Name'
        maxLength='30'
        aria-invalid={errors('user_name')? "true" : "false"}
        ref={register({ required: true })}
         />
        {errors.user_name && errors.user_name.type === "required" && (
          <div role="alert">Name is required<br /></div>
        )}
        <br />
        <input type='email' name='user_email' ref={register} placeholder='Email' />
        <br />
        <textarea name='message' ref={register} placeholder='Message' maxLength='1500' />
        <p className='message-chars-left' >{messageCharsLeft}</p>
        <br />
        <input type='submit' value='Send' />
      </form>

    </div>
  );
}
export default Contact;
